    26→import 'package:baseball_detector_flutter/data/query_runner.dart';
    27→import 'package:baseball_detector_flutter/data/result.dart';
    28→import 'package:baseball_detector_flutter/modules/amplify/amplify.dart';
    29→
    30→abstract class AuthClient {
    31→  Future<Result<Failure, bool>> signInWithPassword(
    32→    String email,
    33→    String password,
    34→    bool saveCredentials,
    35→  );
    36→
    37→  Future<Result<Failure, bool>> signOut();
    38→
    39→  Future<Result<Failure, bool>> changePassword({
    40→    required String newPassword,
    41→    required bool saveCredentials,
    42→  });
    43→
    44→  Future<Result<Failure, bool>> forgotPassword({required String email});
    45→
    46→  Future<Result<Failure, String>> signUp({
    47→    required String email,
    48→    required String password,
    49→    DateTime? birthday,
    50→  });
    51→
    52→  Future<Result<Failure, String>> verifyCode({required String code});
    53→
    54→  Future<Result<Failure, void>> completeSignUp({required String token});
    55→
    56→  Future<Result<Failure, bool>> deleteAccount();
    57→
    58→  Future<bool> get isLoggedIn;
    59→}
    60→
    61→class AuthClientImpl extends AuthClient {
    62→  static final _fc = failureCodeBuilder.category('AAC'); // Auth-AuthClient
    63→  static final _logger = FimberLog('AuthClient');
    64→
    65→  late final APIServerClient _apiClient;
    66→
    67→  QueryRunner get _runner => _apiClient.runner;
    68→
    69→  /// local storage provider
    70→  final ProfileStorage _profileStorage;
    71→
    72→  /// Default constructor
    73→  AuthClientImpl(
    74→    this._profileStorage,
    75→    Locale locale,
    76→    String? appVersion,
    77→  ) {
    78→    _apiClient = APIServerClient(
    79→      locale: locale,
    80→      appVersion: appVersion,
    81→    );
    82→  }
    83→
    84→  @override
    85→
    86→  /// Sign in user to the application with email and password
    87→  Future<Result<Failure, bool>> signInWithPassword(
    88→      String email, String password, bool saveCredentials) async {
    89→    final methodFc = _fc.category('SIP');
    90→
    91→    // Run the query and return result.
    92→    final result = await _runner.runQuery(
    93→      () async {
    94→        if (await AuthUtils.instance.isSignedIn()) {
    95→          await AuthUtils.instance.signOut();
    96→        }
    97→        await Amplify.Auth.signIn(
    98→          username: email,
    99→          password: password,
   100→          options: const SignInOptions(
   101→            pluginOptions: CognitoSignInPluginOptions(
   102→              authFlowType: AuthenticationFlowType.userPasswordAuth,
   103→            ),
   104→          ),
   105→        );
   106→      },
   107→      false,
   108→    );
   109→    if (result.hasLeft) {
   110→      if (result.left is NetworkFailure) {
   111→        return Left(Failure.network(
   112→          code: methodFc.position('001'),
   113→          description: (l10n) =>
   114→              l10n.auth_client__failed_to_authenticate_check_network,
   115→          underlyingException: result.left.underlyingException,
   116→        ));
   117→      }
   118→      if (result.left is InvalidSessionFailure) {
