   131→    late String userId;
   132→    try {
   133→      userId = await AuthUtils.instance.getUserId();
   134→    } catch (e, stackTrace) {
   135→      _logger.e('failed to get userId', ex: e, stacktrace: stackTrace);
   136→      return Left(Failure.undefined(
   137→        code: methodFc.position('002'),
   138→        underlyingException: e,
   139→        stackTrace: stackTrace,
   140→      ));
   141→    }
