   154→    // Get team_id and role of the user using direct API call
   155→    // This avoids circular dependency with Repository
   156→    final userInfoResult = await _apiClient.request(
   157→      method: 'GET',
   158→      path: '/users/me',
   159→      responseMapper: UserDetailResponse.fromJson,
   160→    );
   161→    if (userInfoResult.hasLeft) {
   162→      return Left(userInfoResult.left);
   163→    }
