async createTeamWithItem(
  t: EntityManager,
  data: {
    name?: string;
    ownerUserId: string;
    teamType: TeamType;
    itemId?: string;
    itemName?: string;
    startDate?: Date;
    endDate?: Date;
  },
): Promise<{
  team: Team;
}> {
  const cbuilder = this.getCodeBuilder();

  const item = await t.findOne(Item, {
    where: {
      id: data.itemId,
      name: data.itemName,
    },
  });

  if (!item) {
    throw new CodedInvalidArgumentException(
      this.code,
      this.EC.INVALID_ITEM_ID(cbuilder.build()),
    );
  }

  const team = await t.save(Team, {
    name: data.name ?? '-',
    ownerUserId: data.ownerUserId,
    teamType: data.teamType,
  });

  const startDate = data.startDate ?? new Date('2000-01-01T00:00:00Z');
  const endDate = data.endDate ?? new Date('2100-01-01T00:00:00Z');
  const isActive = +startDate <= +new Date();
  await this.teamItemsPersistence.createTeamItem(t, {
    teamId: team.id,
    itemId: item.id,
    startDate,
    endDate,
    currentBallUsage: 0,
  });

  return {
    team,
  };
}

