      const result = await RequestUtil.retryHttpRequest(async () => {
        const formData = this.createFormData(data);
        return firstValueFrom(
          this.httpService.post(url.toString() + '/', formData, {
            headers: {
              accept: 'application/json',
              'Content-Type': 'multipart/form-data',
              ...formData.getHeaders(),
            },
          }),
        );
      });
      const resourceId = result.data.id;
      this.logger.log(
        `Analysis completed: tid=${data.teamId}/uid=${data.userId}/sid=${data.sessionId}/rid=${resourceId}`,
      );
      return {
        id: resourceId,
      };
    } catch (e) {
      const err = e as AxiosError;
      const errData = err.response?.data as
        | AnalysisServerErrorResponse
        | undefined;
      this.logger.warn(`Failed to analyze video with the following params:`);
      this.logger.warn(data);
      this.logger.error(err.message, err.stack);

      if (err.response?.status === HttpStatus.SERVICE_UNAVAILABLE) {
        throw new CodedServiceUnavailableException(
          this.code,
          this.EC.ANALYSIS_SERVER_UNAVAILABLE(cbuilder.build()),
        );
      } else if (errData?.code == 'E-DB-CONNECTION-ERROR') {
        throw new CodedException(
          this.code,
          this.EC.ANALYSIS_SERVER_CONNECTION(cbuilder.build()),
        );
      } else if (errData?.code == 'E-CRITICAL-ERROR') {
        throw new CodedException(
          this.code,
          this.EC.ANALYSIS_SERVER_CRITICAL(cbuilder.build()),
        );
      } else if (errData?.code == 'E-VIDEO-OPEN-ERROR') {
        throw new CodedInvalidArgumentException(
          this.code,
          this.EC.COULDNT_OPEN_VIDEO(cbuilder.build()),
        );
      } else {
        // For example, this occurs when API-Analysis connection shut down (or unexpected).
        throw new CodedException(
          this.code,
          this.EC.FAILED_TO_UPLOAD_VIDEO(cbuilder.build()),
        );
      }
    }
  }

  @CodedMethod('RALVD')
  async reanalyzeVideo(data: {
    userId: string;
    resourceId: string;
    teamId: string;
  }) {
    const cbuilder = this.getCodeBuilder();
    const formData = new FormData();

    formData.append('secret_key', this.configProvider.config.analyzeKey);
    formData.append('profile_id', data.userId);
    formData.append('team_id', data.teamId);

    const url = StringUtil.buildUrl(
      this.configProvider.config.analyzeServerUrl,
      `/analyze/${data.resourceId}`,
    );
    try {
      await RequestUtil.retryHttpRequest(async () => {
        return firstValueFrom(
          this.httpService.patch(url.toString(), formData, {
            headers: {
              accept: 'application/json',
              'Content-Type': 'multipart/form-data',
              ...formData.getHeaders(),
            },
          }),
        );
      });
      this.logger.log(
        `Analysis completed(re-analyze): tid=${data.teamId}/uid=${data.userId}/rid=${data.resourceId}`,
      );
    } catch (e) {
      const err = e as AxiosError;
      const errData = err.response?.data as
        | AnalysisServerErrorResponse
        | undefined;
      this.logger.error(err.message, err.stack);
      if (errData?.code == 'E-DB-CONNECTION-ERROR') {
        throw new CodedException(
          this.code,
          this.EC.ANALYSIS_SERVER_CONNECTION(cbuilder.build()),
        );
      } else if (errData?.code == 'E-CRITICAL-ERROR') {
        throw new CodedException(
          this.code,
          this.EC.ANALYSIS_SERVER_CRITICAL(cbuilder.build()),
        );
      } else {
        throw new CodedException(
          this.code,
          this.EC.FAILED_TO_UPLOAD_VIDEO(cbuilder.build()),
        );
      }
    }
  }
}

