  async analyzeVideoForTeam(
    requesterUid: string,
    teamId: string,
    sessionId: string,
    data: VideoAnalyzeDtoValidated & {
      originalFilename: string;
    },
    localFilePath: string,
    accessToken: string,
  ): Promise<{
    resource: {
      id: string;
    };
  }> {
    const cbuilder = this.getCodeBuilder();
    const now = new Date();

    const tranResult = await this.datasource.manager.transaction(async (t) => {
      const session = await t.findOne(Session, {
        where: {
          id: sessionId,
          teamId,
        },
      });

      if (!session) {
        throw new CodedInvalidArgumentException(
          this.code,
          this.EC.INVALID_SESSION_ID(cbuilder.build()),
        );
      }

      if (data.resourceId) {
        const resource = await t.findOne(Resource, {
          where: {
            id: data.resourceId,
          },
          relations: {
            session: true,
          },
        });
        // The directed resource ID (`data.resourceId`) is already used in another team (only for attacking).
        if (resource && resource.session.teamId != teamId) {
          throw new CodedInvalidArgumentException(
            this.code,
            this.EC.THE_RESOURCE_ID_IS_ALREADY_USED(cbuilder.build()),
          );
        }

        // The resource is already analized (below comments).
        if (resource) {
          return {
            resource,
          };
        }
      }

      await this.teamItemsPersistence.verifyTeamItemBallAvailability(t, {
        teamId,
        count: 1,
      });

      return {
        resource: null,
      };
    });

    // The resource is already analyzed with the resourceId generated in the front app.
    // This case occurs when the ID-consistency with the front app is broken.
    if (tranResult.resource) {
      this.logger.warn(
        `Analyze-API is requested again with rid=${data.resourceId}. Check the implementation of the front app.`,
      );
      return {
        resource: {
          id: tranResult.resource.id,
        },
      };
    }

    const result = await this.analysisProvider.analyzeVideo({
      userId: requesterUid,
      sessionId: sessionId,
      teamId: teamId,
      ...data,
      localFilePath,
    });

    return {
      resource: {
        id: result.id,
      },
    };
  }

  @CodedMethod('RAZ')
  async reanalyze(
    teamId: string,
    sessionId: string,
    resourceId: string,
    data: {
      userId: string;
    },
    checkUserId: boolean,
  ): Promise<boolean> {
    const cbuilder = this.getCodeBuilder();
    const now = new Date();

    await this.datasource.manager.transaction(async (t) => {
      const checkingResource =
        await this.resourcesPersistence.checkResourceAccess(
          t,
          teamId,
          sessionId,
          resourceId,
          checkUserId ? data.userId : undefined,
        );

      if (!checkingResource.exists) {
        throw new CodedInvalidArgumentException(
          this.code,
          this.EC.INVALID_RESOURCE_ID(cbuilder.build()),
        );
      }

      await this.teamItemsPersistence.verifyTeamItemBallAvailability(t, {
        teamId,
        count: 1,
      });
    });

    await this.analysisProvider.reanalyzeVideo({
      userId: data.userId,
      resourceId,
      teamId,
    });

    return true;
  }
}

