  const TeamItemData({
    required this.id,
    required this.teamId,
    this.teamSubscriptionId,
    required this.itemId,
    this.terminatedAt,
    required this.isLatest,
  });

  final String id;
  final String teamId;
  final String? teamSubscriptionId;
  final String itemId;
  final DateTime? terminatedAt;
  final bool isLatest;
}

